703	fn inject_locked_keybinds(base: &str) -> (String, bool) {
704	    let key = "locked {";
705	    let Some(start) = base.find(key) else {
706	        return (base.to_string(), false);
707	    };
708	    // Byte index of the `{` itself - balance from here.
709	    let open = start + key.len() - 1;
710	    let bytes = base.as_bytes();
711	    let mut depth: i32 = 0;
712	    let mut close = None;
713	    for (i, b) in bytes.iter().enumerate().skip(open) {
714	        match b {
715	            b'{' => depth += 1,
716	            b'}' => {
717	                depth -= 1;
718	                if depth == 0 {
719	                    close = Some(i);
720	                    break;
721	                }
722	            }
723	            _ => {}
724	        }
725	    }
726	    let Some(close) = close else {
727	        return (base.to_string(), false);
728	    };
729	    let extras = locked_extra_binds();
730	    let mut out = String::with_capacity(base.len() + extras.len());
731	    out.push_str(&base[..close]);
732	    out.push_str(&extras);
733	    out.push_str(&base[close..]);
734	    (out, true)
735	}
736	
737	/// The body of bindings injected into the existing locked block by
738	/// [`inject_locked_keybinds`]. Indentation matches the typical eight-space
739	/// inner indent of a Zellij `mode { bind ... }` body so the spliced lines
740	/// sit visually alongside whatever was already there. The Alt-N and Ctrl-Q
741	/// binds reuse the cockpit's pipe-gated rewrites so spawn and quit still go
742	/// through the sidebar gatekeeper. Ctrl-S mirrors Zellij's stock scroll-mode
743	/// entry binding so a one-keystroke pane-bounded selection / scrollback path
744	/// is available even while a content pane is auto-locked.
745	///
746	/// PageUp / PageDown go here (rather than a top-level `shared { ... }`
747	/// block) so they only fire on the auto-locked content pane - directly
748	/// binding to `PageScrollUp` / `PageScrollDown` keeps the gesture
749	/// transparent (Zellij scrolls the pane's scrollback and auto-returns on
750	/// next I/O) without intercepting the keys on the sidebar plugin panes,
751	/// which stay in Normal mode and whose own `handle_key` page-steps the
752	/// list cursor.
753	fn locked_extra_binds() -> String {
754	    let focus_binds = focus_pane_binds();
755	    format!(
756	        "        bind \"Ctrl s\" {{ SwitchToMode \"scroll\"; }}\n        \
757	         bind \"PageUp\" {{ PageScrollUp; }}\n        \
758	         bind \"PageDown\" {{ PageScrollDown; }}\n        \
759	         bind \"Alt Left\" {{ MoveFocusOrTab \"Left\"; }}\n        \
760	         bind \"Alt Right\" {{ MoveFocusOrTab \"Right\"; }}\n        \
761	         bind \"Alt Up\" {{ MoveFocus \"Up\"; }}\n        \
762	         bind \"Alt Down\" {{ MoveFocus \"Down\"; }}\n        \
763	         {NEW_PANE_BIND_TO}\n        \
764	         {QUIT_BIND_TO}\n        \
765	         {SEARCH_BIND_TO}\n        \
766	         {focus_binds}\n    "
767	    )
768	}
769	
770	/// Force `mouse_mode true` in the generated config. Replaces an explicit
771	/// `mouse_mode false` if the user's base config has one; otherwise appends
772	/// the line iff `mouse_mode true` is not already present. Either way, the
773	/// generated cockpit config carries an explicit on, so the auto-locked mode
774	/// flip never lands users in a state where mouse events stop reaching their
775	/// content panes.
776	fn ensure_mouse_mode_enabled(base: &str) -> String {
777	    let flipped = base.replace(MOUSE_MODE_OFF, MOUSE_MODE_ON);
778	    if flipped.contains(MOUSE_MODE_ON) {
779	        return flipped;
780	    }
781	    let mut out = flipped;
782	    if !out.ends_with('\n') {
783	        out.push('\n');
784	    }
785	    out.push_str(MOUSE_MODE_ON);
786	    out.push('\n');
787	    out
788	}
789	
790	/// Force pane frames on. The cockpit signals focus through the focused pane's
791	/// frame color (see [`apply_focus_theme`]), which is invisible with frames off.
792	/// Zellij's stock default is already on, so this only rewrites an explicit
793	/// `pane_frames false`; an unset config keeps the on-by-default behavior.
794	fn ensure_pane_frames_enabled(base: &str) -> String {
795	    base.replace(PANE_FRAMES_OFF, PANE_FRAMES_ON)
796	}
797	
798	/// Make the focused pane unmistakable by defining and activating the cockpit's
799	/// `panopt` frame theme - unless the user has chosen their own theme, in which
800	/// case we leave it alone (activating ours would swap every non-frame color
801	/// back to Zellij's default, since our theme is intentionally partial). When
802	/// skipped, the returned `Option` carries the user's theme name so the caller
803	/// can explain the gap.
804	///
805	/// When applying: the `panopt` theme body is spliced into an existing
806	/// top-level `themes { ... }` block if the base config has one (Zellij reads
807	/// only the *first* such block, so a second appended block would be silently
808	/// ignored - the same gotcha as keybinds), otherwise a fresh `themes` block is
809	/// appended. Either way a `theme "panopt"` directive is appended to activate it.
810	fn apply_focus_theme(base: &str) -> (String, Option<String>) {
811	    if let Some(name) = active_theme_name(base) {
812	        return (base.to_string(), Some(name));
813	    }
814	    let with_def = match splice_into_themes_block(base, FOCUS_THEME_DEF) {
815	        Some(spliced) => spliced,
816	        None => {
817	            let mut out = String::from(base);
818	            if !out.is_empty() && !out.ends_with('\n') {
819	                out.push('\n');
820	            }
821	            out.push_str("themes {\n");
822	            out.push_str(FOCUS_THEME_DEF);
823	            out.push_str("}\n");
824	            out
825	        }
826	    };
827	    let mut out = with_def;
828	    if !out.ends_with('\n') {
829	        out.push('\n');
830	    }
831	    out.push_str(&format!("theme \"{FOCUS_THEME_NAME}\"\n"));
832	    (out, None)
833	}
834	
835	/// The name in an *active* (uncommented) top-level `theme "<name>"` directive,
836	/// or `None` when the base config leaves the theme at Zellij's default - the
837	/// stock dump keeps that line commented. The trailing space in the `theme `
838	/// prefix keeps `theme_dir` from matching.
839	fn active_theme_name(base: &str) -> Option<String> {
840	    base.lines().find_map(|line| {
841	        let line = line.trim_start();
842	        if line.starts_with("//") {
843	            return None;
844	        }
845	        let rest = line.strip_prefix("theme ")?.trim_start();
846	        let inner = rest.strip_prefix('"')?;
847	        let end = inner.find('"')?;
848	        Some(inner[..end].to_string())
849	    })
850	}
851	
852	/// Splice `def` (an indented `name { ... }` theme body) in just before the
853	/// closing brace of the first top-level `themes {` block, returning the new
854	/// config - or `None` when the base config has no such block. Walks from the
855	/// block's opening brace and balances braces to find its matching close, the
856	/// same hand-rolled approach [`inject_locked_keybinds`] uses (no KDL-parser
857	/// dep). Only the *first* `themes` block is honored by Zellij, so that is the
858	/// one we extend.
859	fn splice_into_themes_block(base: &str, def: &str) -> Option<String> {
860	    let key = "themes {";
861	    let start = base.find(key)?;
862	    // Skip a commented occurrence (`// themes {`): require the line to start
863	    // with `themes` after trimming, otherwise keep looking is overkill - the
864	    // dumped config never comments a `themes {` header, and a user one is
865	    // uncommented. Guard the obvious comment case all the same.
866	    let line_start = base[..start].rfind('\n').map_or(0, |i| i + 1);
867	    if base[line_start..start].trim_start().starts_with("//") {
868	        return None;
869	    }
870	    let open = start + key.len() - 1;
871	    let mut depth: i32 = 0;
872	    let mut close = None;
873	    for (i, b) in base.as_bytes().iter().enumerate().skip(open) {
874	        match b {
875	            b'{' => depth += 1,
876	            b'}' => {
877	                depth -= 1;
878	                if depth == 0 {
879	                    close = Some(i);
880	                    break;
881	                }
882	            }
883	            _ => {}
884	        }
885	    }
886	    let close = close?;
887	    let mut out = String::with_capacity(base.len() + def.len());
888	    out.push_str(&base[..close]);
889	    out.push_str(def);
890	    out.push_str(&base[close..]);
891	    Some(out)
892	}
893	
894	/// Retarget every CloseFocus/CloseTab/Quit keybind to `Run` of
895	/// `zellij action pipe`, sending the request to the sidebar plugin instead of
896	/// acting immediately. The plugin gates these against active items and either
897	/// refuses (showing a floating dialog) or force-closes via the plugin API,
898	/// which bypasses the rewritten keybinds.
899	///
