/// Zellij's stock pane-mode (`Ctrl-p`) split keys, retargeted to the same
/// `panopt:spawn-blank-pane` pipe as Alt-N. Without this, `Ctrl-p` then
/// `n`/`d`/`r`/`s` reaches Zellij's native `NewPane`, which splits whatever
/// pane is focused - and a sidebar plugin pane sits in Normal mode where pane
/// mode is reachable, so the gesture shreds the fixed 25% sidebar column. The
/// plugin's `spawn_blank_pane` gate already refuses the pipe when a sidebar
/// pane is focused (and routes it into a viewer slot otherwise), so funneling
/// every split key through it collapses the directional split semantics into
/// the cockpit's one swap-into-slot model - the same treatment Alt-N gets.
/// `SwitchToMode "Normal"` is preserved so the keypress still leaves pane
/// mode. Pane mode is unreachable from an auto-locked content pane, so no
/// locked-block variant is needed. Each FROM is the exact text the defaults
/// dump emits; see [`NEW_PANE_BIND_FROM`] for why the cockpit pipes through
/// `zellij action pipe` rather than `MessagePlugin`.
const PANE_SPLIT_BINDS: &[(&str, &str)] = &[
    (
        r#"bind "n" { NewPane; SwitchToMode "Normal"; }"#,
        r#"bind "n" { Run "zellij" "action" "pipe" "--name" "panopt:spawn-blank-pane" "--plugin-configuration" "mode=todos" { close_on_exit true; }; SwitchToMode "Normal"; }"#,
    ),
    (
        r#"bind "d" { NewPane "Down"; SwitchToMode "Normal"; }"#,
        r#"bind "d" { Run "zellij" "action" "pipe" "--name" "panopt:spawn-blank-pane" "--plugin-configuration" "mode=todos" { close_on_exit true; }; SwitchToMode "Normal"; }"#,
    ),
    (
        r#"bind "r" { NewPane "Right"; SwitchToMode "Normal"; }"#,
        r#"bind "r" { Run "zellij" "action" "pipe" "--name" "panopt:spawn-blank-pane" "--plugin-configuration" "mode=todos" { close_on_exit true; }; SwitchToMode "Normal"; }"#,
    ),
