/// Retarget Zellij's pane-mode split keys (`n`/`d`/`r`/`s`) to the same
/// spawn-blank-pane pipe Alt-N uses, so they cannot split a focused sidebar
/// pane. Returns the count of binds actually rewritten; the caller warns when
/// it is short of [`PANE_SPLIT_BINDS`]'s length so the user knows a
/// reformatted config left the gate with gaps. See [`PANE_SPLIT_BINDS`].
fn retarget_pane_mode_splits(base: &str) -> (String, usize) {
    let mut out = base.to_string();
    let mut changed = 0;
    for (from, to) in PANE_SPLIT_BINDS {
        let next = out.replace(from, to);
        if next != out {
            changed += 1;
            out = next;
        }
    }
    (out, changed)
}

