#[test]
fn retarget_pane_mode_splits_funnels_every_split_key_through_the_pipe() {
    // The four stock pane-mode split binds, exactly as the defaults dump.
    let base = "\
        pane {\n        \
            bind \"n\" { NewPane; SwitchToMode \"Normal\"; }\n        \
            bind \"d\" { NewPane \"Down\"; SwitchToMode \"Normal\"; }\n        \
            bind \"r\" { NewPane \"Right\"; SwitchToMode \"Normal\"; }\n        \
            bind \"s\" { NewPane \"stacked\"; SwitchToMode \"Normal\"; }\n    \
        }\n";
    let (tweaked, changed) = retarget_pane_mode_splits(base);
    assert_eq!(changed, PANE_SPLIT_BINDS.len());
    // No native NewPane survives - every split key now pipes the cockpit's
    // spawn-blank-pane request, which the plugin gates on sidebar focus.
    assert!(!tweaked.contains("NewPane"), "{tweaked}");
    assert_eq!(
        tweaked.matches("\"panopt:spawn-blank-pane\"").count(),
        PANE_SPLIT_BINDS.len()
    );
    // The mode-exit is preserved so the keypress still leaves pane mode.
    assert_eq!(
        tweaked.matches("SwitchToMode \"Normal\"").count(),
        PANE_SPLIT_BINDS.len()
    );
}

